Create a file named 'bridge.ts' with the following content:

import 'dotenv/config';
import { ethers } from 'ethers';
import { Builder } from '@paraspell/sdk';

const PRIVATE_KEY = process.env.PRIVATE_KEY!;
const ETH_RPC_URL = process.env.ETH_RPC_URL!;
const DEST = process.env.DEST_POLKADOT_ADDRESS!;
// Token to bridge — WETH on Ethereum mainnet
const TOKEN_SYMBOL = 'WETH';
// Amount in smallest units (WETH has 18 decimals; 1e15 = 0.001 WETH)
const AMOUNT = '1000000000000000';

async function main() {
  const provider = new ethers.JsonRpcProvider(ETH_RPC_URL);
  const signer = new ethers.Wallet(PRIVATE_KEY, provider);
  console.log('Sender:', signer.address);
  const bal = await provider.getBalance(signer.address);
  console.log('ETH balance:', ethers.formatEther(bal));

  const tx = await Builder()
    .from('Ethereum')
    .to('AssetHubPolkadot')
    .currency({ symbol: TOKEN_SYMBOL, amount: AMOUNT })
    .address(DEST)
    .buildEthTransfer({ ethSigner: signer });

  console.log('Submitting Snowbridge transfer...');
  const receipt = await tx.wait();
  console.log('Transaction hash:', receipt.hash);
  console.log('Relay in progress — monitor at https://bridge.polkadot.io/');
  console.log('Tokens typically arrive in 15-30 minutes.');
}

main().catch(e => { console.error(e); process.exit(1); });

Substitutions: (1) TOKEN_SYMBOL — change 'WETH' to the ERC-20 symbol you are bridging (must be supported by Snowbridge). (2) AMOUNT — change '1000000000000000' to your intended amount in smallest units; WETH has 18 decimals so 1e18 = 1 WETH. (3) If buildEthTransfer is not available in your installed @paraspell/sdk version, consult https://paraspell.github.io/docs for the correct Snowbridge API.

Create /etc/nginx/sites-available/polkadot-wss with the following content, replacing YOUR_DOMAIN with your domain name:

server {
    listen 443 ssl;
    server_name YOUR_DOMAIN;

    ssl_certificate /etc/letsencrypt/live/YOUR_DOMAIN/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/YOUR_DOMAIN/privkey.pem;

    location / {
        proxy_pass http://localhost:9944;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "Upgrade";
        proxy_set_header Host $host;
        proxy_read_timeout 86400;
    }
}

server {
    listen 80;
    server_name YOUR_DOMAIN;
    return 301 https://$host$request_uri;
}

Then enable the site and reload:
sudo ln -s /etc/nginx/sites-available/polkadot-wss /etc/nginx/sites-enabled/
sudo nginx -t && sudo systemctl reload nginx

For Apache2 instead of nginx, create /etc/apache2/sites-available/polkadot-wss.conf:

<VirtualHost *:443>
    ServerName YOUR_DOMAIN
    SSLEngine on
    SSLCertificateFile /etc/letsencrypt/live/YOUR_DOMAIN/fullchain.pem
    SSLCertificateKeyFile /etc/letsencrypt/live/YOUR_DOMAIN/privkey.pem
    ProxyRequests Off
    ProxyPass / ws://localhost:9944/
    ProxyPassReverse / ws://localhost:9944/
    RewriteEngine On
