Write the pallet implementation in pallets/counter/src/lib.rs. A minimal counter pallet contains:

#![cfg_attr(not(feature = "std"), no_std)]

pub use pallet::*;

#[frame_support::pallet]
pub mod pallet {
    use frame_support::pallet_prelude::*;
    use frame_system::pallet_prelude::*;

    #[pallet::pallet]
    pub struct Pallet<T>(_);

    #[pallet::config]
    pub trait Config: frame_system::Config {
        type RuntimeEvent: From<Event<Self>> + IsType<<Self as frame_system::Config>::RuntimeEvent>;
        #[pallet::constant]
        type MaxValue: Get<u32>;
    }

    #[pallet::storage]
    pub type CounterValue<T> = StorageValue<_, u32, ValueQuery>;

    #[pallet::event]
    #[pallet::generate_deposit(pub(super) fn deposit_event)]
    pub enum Event<T: Config> {
        CounterIncremented { new_value: u32 },
        CounterDecremented { new_value: u32 },
    }

    #[pallet::error]
    pub enum Error<T> {
        CounterOverflow,
        CounterUnderflow,
    }

    #[pallet::call]
    impl<T: Config> Pallet<T> {
        #[pallet::call_index(0)]
        #[pallet::weight(10_000)]
        pub fn increment(origin: OriginFor<T>) -> DispatchResult {
            ensure_signed(origin)?;
            let val = CounterValue::<T>::get();
            let new_val = val.checked_add(1).ok_or(Error::<T>::CounterOverflow)?;
            ensure!(new_val <= T::MaxValue::get(), Error::<T>::CounterOverflow);
            CounterValue::<T>::put(new_val);
            Self::deposit_event(Event::CounterIncremented { new_value: new_val });
            Ok(())
        }

        #[pallet::call_index(1)]
        #[pallet::weight(10_000)]
        pub fn decrement(origin: OriginFor<T>) -> DispatchResult {
            ensure_signed(origin)?;
            let val = CounterValue::<T>::get();
            let new_val = val.checked_sub(1).ok_or(Error::<T>::CounterUnderflow)?;
            CounterValue::<T>::put(new_val);
            Self::deposit_event(Event::CounterDecremented { new_value: new_val });
            Ok(())
        }
    }
}

The MaxValue constant bounds the counter to prevent overflow. checked_add/checked_sub replace panicking arithmetic.

